/**
 * HarmonyDialog — standard dialog for data entry and interactive workflows.
 *
 * Use HarmonyDialog whenever the user needs to fill in a form, view or edit
 * data, or perform any multi-step interaction while staying in context.
 * For simple yes/no confirmations or destructive-action warnings, use
 * HarmonyAlertDialog instead.
 *
 * ## Choosing the right dialog
 * | Scenario                                  | Component            |
 * |-------------------------------------------|----------------------|
 * | Create / edit form                        | HarmonyDialog        |
 * | View details / read-only panel            | HarmonyDialog        |
 * | Upload, import, or complex wizard         | HarmonyDialog        |
 * | "Are you sure you want to delete X?"      | HarmonyAlertDialog   |
 * | "Session about to expire" warning         | HarmonyAlertDialog   |
 *
 * ## Usage examples
 *
 * ### 1 · Create / edit form (most common)
 * ```tsx
 * const [open, setOpen] = useState(false);
 * const { mutate, isPending } = useCreateEmployee();
 *
 * <Button onClick={() => setOpen(true)}>Add Employee</Button>
 *
 * <HarmonyDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   title="Add Employee"
 *   description="Fill in the employee's details. Required fields are marked *."
 *   submitLabel="Save"
 *   onSubmit={handleSubmit}
 *   isSubmitting={isPending}
 * >
 *   <EmployeeForm />
 * </HarmonyDialog>
 * ```
 *
 * ### 2 · Read-only detail view with a custom footer
 * ```tsx
 * <HarmonyDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   title="Employee Profile"
 *   footerChildren={
 *     <>
 *       <Button variant="ghost" onClick={() => setOpen(false)}>Close</Button>
 *       <Button onClick={() => navigate(`/employees/${id}`)}>Open Full Profile</Button>
 *     </>
 *   }
 * >
 *   <ProfileSummary employee={employee} />
 * </HarmonyDialog>
 * ```
 *
 * ### 3 · No footer (closed via the X button only)
 * ```tsx
 * <HarmonyDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   title="Payslip Preview"
 *   showFooter={false}
 * >
 *   <PayslipPdf url={payslipUrl} />
 * </HarmonyDialog>
 * ```
 *
 * ### 4 · Long form with internal scroll (body scrolls, header/footer stay fixed)
 * ```tsx
 * <HarmonyDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   title="Leave Request"
 *   scrollable
 *   onSubmit={handleSubmit}
 *   submitLabel="Submit Request"
 *   isSubmitting={isPending}
 * >
 *   <LeaveRequestForm />
 * </HarmonyDialog>
 * ```
 *
 * ### 5 · Smaller size for a quick action (e.g. change status)
 * ```tsx
 * <HarmonyDialog
 *   open={open}
 *   onOpenChange={setOpen}
 *   title="Change Status"
 *   size="md"
 *   onSubmit={handleSubmit}
 *   submitLabel="Update"
 *   isSubmitting={isPending}
 * >
 *   <StatusSelector current={status} />
 * </HarmonyDialog>
 * ```
 */

import { Loader2 } from "lucide-react";
import { Button } from "@/shadcn/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/shadcn/components/ui/dialog";
import { cn } from "@/shadcn/lib/utils";

// ---------------------------------------------------------------------------
// Size map — tailwind-merge overrides the sm:max-w-md baked into DialogContent
// ---------------------------------------------------------------------------
const SIZE_CLASSES: Record<HarmonyDialogSize, string> = {
  sm: "sm:max-w-sm",
  md: "sm:max-w-md",
  lg: "sm:max-w-lg",
  xl: "sm:max-w-xl",
  "2xl": "sm:max-w-2xl",
  "3xl": "sm:max-w-3xl",
  full: "sm:max-w-[calc(100vw-2rem)]",
};

export type HarmonyDialogSize = "sm" | "md" | "lg" | "xl" | "2xl" | "3xl" | "full";

export interface HarmonyDialogProps {
  // ── open state ──────────────────────────────────────────────────────────
  /** Controls whether the dialog is visible. */
  open: boolean;
  /** Called when the dialog requests to close (overlay click, Escape key, X button). */
  onOpenChange: (open: boolean) => void;

  // ── content ─────────────────────────────────────────────────────────────
  /** Dialog heading — shown in the header bar. Required. */
  title: string;
  /**
   * Optional subtitle rendered below the title in muted text.
   * Keep this to one short sentence; detailed instructions belong inside children.
   */
  description?: string;
  /** The main body of the dialog — forms, detail views, upload panels, etc. */
  children?: React.ReactNode;

  // ── layout ──────────────────────────────────────────────────────────────
  /**
   * Max-width breakpoint.
   * @default "xl"  (~576 px)
   *
   * | size  | approx width |
   * |-------|-------------|
   * | sm    | 384 px      |
   * | md    | 448 px      |
   * | lg    | 512 px      |
   * | xl    | 576 px      |
   * | 2xl   | 672 px      |
   * | 3xl   | 768 px      |
   * | full  | 100vw − 2rem |
   */
  size?: HarmonyDialogSize;
  /**
   * When true the body scrolls independently so the header and footer stay on
   * screen for tall forms. The body is capped at 60% of the viewport height.
   * @default false
   */
  scrollable?: boolean;
  /** Whether to render the close (×) button in the top-right corner. @default true */
  showCloseButton?: boolean;

  // ── footer — auto mode ───────────────────────────────────────────────────
  /**
   * Called when the primary (submit) button is clicked.
   * Providing this prop activates the auto-generated Cancel + Submit footer.
   * Omit it if you supply `footerChildren` or set `showFooter={false}`.
   */
  onSubmit?: () => void;
  /** Label for the submit button. @default "Save" */
  submitLabel?: string;
  /** Called when Cancel is clicked; falls back to `onOpenChange(false)`. */
  onCancel?: () => void;
  /** Label for the cancel button. @default "Cancel" */
  cancelLabel?: string;
  /**
   * Shows a loading spinner on the submit button and disables both buttons.
   * Pair this with your mutation's `isPending` state.
   * @default false
   */
  isSubmitting?: boolean;
  /** Disables the submit button without showing a spinner. @default false */
  submitDisabled?: boolean;

  // ── footer — custom mode ─────────────────────────────────────────────────
  /**
   * Renders custom footer content instead of the auto Cancel+Submit buttons.
   * Takes precedence over `onSubmit` / `submitLabel` / `cancelLabel`.
   *
   * @example
   * ```tsx
   * footerChildren={
   *   <>
   *     <Button variant="ghost" onClick={() => setOpen(false)}>Close</Button>
   *     <Button onClick={handlePrint}>Print</Button>
   *   </>
   * }
   * ```
   */
  footerChildren?: React.ReactNode;

  // ── footer — disable ─────────────────────────────────────────────────────
  /**
   * Set to false to suppress the footer entirely.
   * The dialog can still be dismissed via the X button or Escape key.
   * @default true (footer is shown when onSubmit or footerChildren is provided)
   */
  showFooter?: boolean;

  /** Additional classes applied to the DialogContent wrapper. */
  className?: string;
}

/**
 * HarmonyDialog — controlled modal for data-interaction flows.
 *
 * Wraps the shadcn Dialog primitives with Harmony design conventions:
 * unified sizing, a built-in loading-aware footer, and consistent header
 * structure. All props are documented above on {@link HarmonyDialogProps}.
 */
export function HarmonyDialog({
  open,
  onOpenChange,
  title,
  description,
  children,
  size = "xl",
  scrollable = false,
  showCloseButton = true,
  onSubmit,
  submitLabel = "Save",
  onCancel,
  cancelLabel = "Cancel",
  isSubmitting = false,
  submitDisabled = false,
  footerChildren,
  showFooter = true,
  className,
}: HarmonyDialogProps) {
  const handleCancel = () => {
    onCancel?.();
    onOpenChange(false);
  };

  // Determine what (if anything) to render in the footer.
  const hasFooter = showFooter && (footerChildren != null || onSubmit != null);

  const footer = hasFooter ? (
    <DialogFooter>
      {footerChildren ?? (
        <>
          <Button
            variant="secondary"
            onClick={handleCancel}
            disabled={isSubmitting}
          >
            {cancelLabel}
          </Button>
          <Button
            variant="default"
            onClick={onSubmit}
            disabled={isSubmitting || submitDisabled}
          >
            {isSubmitting && <Loader2 className="animate-spin" />}
            {submitLabel}
          </Button>
        </>
      )}
    </DialogFooter>
  ) : null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent
        className={cn(SIZE_CLASSES[size], className)}
        showCloseButton={showCloseButton}
      >
        <DialogHeader>
          <DialogTitle>{title}</DialogTitle>
          {description && <DialogDescription>{description}</DialogDescription>}
        </DialogHeader>

        {children && (
          <div
            className={
              scrollable
                ? "overflow-y-auto max-h-[60vh] pr-1"
                : undefined
            }
          >
            {children}
          </div>
        )}

        {footer}
      </DialogContent>
    </Dialog>
  );
}
